import { Fixture } from '../../objects/fixture';
import './fixtures.css';

interface FixtureItemComponentProps
{
    fixture: Fixture
}

// Here we are passing in the object we want as props and deconstructing it. 
// We do need an Id for each row but that is in the calling code where we are .Map the array
// <ResultsRow key={fixture.Id} {fixture=h}
const FixtureItem = ({fixture} : FixtureItemComponentProps) => {
    
    let resultClassToAdd = "";
    let result = "";
    let gameType = "";
    
    switch(fixture.result)
    {
        case 0:
            resultClassToAdd = "table-success";
            result = "W";
            break;
        case 1:            
            resultClassToAdd = "table-danger";
            result = "L";
            break;
        case 2:
            resultClassToAdd = "table-secondary";
            result = "D";
            break;
    }    

    switch (fixture.type)
    {
        case 0:
        gameType = "L";
        break;

        case 1:
        gameType = "F";
        break;

        case 2:
        gameType = "C";
        break;
    }
    
    return(  
        <>
        <tr>
            <td >{new Date(fixture.date).toLocaleDateString("en-UK")}</td>            
            <td className={resultClassToAdd}>{result}</td>
            <td >{fixture.homeTeam}</td>
            <td>{fixture.homeTeamScore} v {fixture.awayTeamScore}</td>
            <td>{fixture.awayTeam}</td>            
            <td>{fixture.pts}</td>
            <td>{gameType}</td>
        </tr>        
        {console.log(fixture)}
        </>   
    )
}               
export default FixtureItem;
